        int n = s.size(), dp[n + 1], res = 0;
        memset(dp, 0, sizeof(dp));
        for (int i = n - 1; i >= 0; --i) {
            int num = 0;
            for (int j = i; j >= 0; --j) {
                num = num * 2 + (s[j] - '0');
                if (num <= k) dp[i] = max(dp[i], dp[j + 1] + 1);
            }
            res = max(res, dp[i]);
        }
        return res;
    }
};
